```class Solution {
public:
    int countKDifference(vector<int>& nums, int k) {
        unordered_map<int, int> count;
        int res = 0;
        for (int num : nums) {
            res += count[num - k] + count[num + k];
            count[num]++;
        }
        return res;
    }
};
